from __future__ import annotations

import importlib.util
from pathlib import Path
from controlplane.cli import (
    _score_anchor_coherence,
    _score_backlog_projected_hypothesis_coherence,
    _score_joint_pending_hypothesis_pair,
    _score_joint_pending_promotion_pair,
    _score_joint_recovery_hypothesis_pair,
    _score_joint_recovery_pair,
)


def _load_compiled_test_module():
    pyc_path = Path(__file__).with_name("__pycache__") / "test_cli.cpython-313.pyc"
    spec = importlib.util.spec_from_file_location("_compiled_test_cli", pyc_path)
    if spec is None or spec.loader is None:
        raise RuntimeError(f"Unable to load compiled test module from {pyc_path}")
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    return module


_compiled = _load_compiled_test_module()

for _name in dir(_compiled):
    if _name.startswith("__") and _name not in {"__doc__"}:
        continue
    globals()[_name] = getattr(_compiled, _name)


def _write_simple_backlog(backlog_path: Path, *, best_objective: str) -> None:
    backlog_path.write_text(
        json.dumps(
            [
                {
                    "experiment_id": "exp_low",
                    "objective": "Low value objective",
                    "expected_information_gain": 0.20,
                    "risk_reduction": 0.10,
                    "cost_score": 0.10,
                },
                {
                    "experiment_id": "exp_best",
                    "objective": best_objective,
                    "hypothesis_links": ["h_exp_best"],
                    "expected_information_gain": 0.80,
                    "risk_reduction": 0.50,
                    "cost_score": 0.20,
                },
            ]
        )
        + "\n",
        encoding="utf-8",
    )


def test_init_creates_campaign_workspace_with_resume_assessment(tmp_path: Path) -> None:
    target = tmp_path / "demo"

    result = runner.invoke(app, ["init", str(target), "--question", "Does X help Y?"])

    assert result.exit_code == 0
    state = json.loads((target / "campaign_state.json").read_text(encoding="utf-8"))
    assert state["campaign_id"] == "demo"
    assert state["status"] == "active"
    assert state["iterations_run"] == 0
    assert state["campaign_summary"]["research_question"] == "Does X help Y?"
    assert state["campaign_summary"]["resume_ready"] is False
    assert state["campaign_summary"]["resume_reasons"] == ["latest_iteration_missing"]
    assert state["resume_assessment"] == {
        "resume_ready": False,
        "reasons": ["latest_iteration_missing"],
    }
    assert state["campaign_lifecycle"] == "not_started"
    assert state["campaign_backlog"]["selection_history"] == []
    assert state["campaign_hypotheses"]["selection_history"] == []
    assert state["campaign_hypotheses"]["frontier_history"] == []
    assert state["backlog_summary"] == {
        "selection_ready": False,
        "active_experiment_id": None,
        "active_objective": None,
        "promising_candidates": [],
        "blocked_candidates": [],
        "unproven_candidates": [],
        "recommended_anchor_experiment_id": None,
        "recommended_anchor_status": None,
    }
    assert state["hypothesis_summary"] == {
        "selection_ready": False,
        "active_hypotheses": [],
        "supported_hypotheses": [],
        "unstable_hypotheses": [],
        "mixed_hypotheses": [],
        "unknown_hypotheses": [],
        "recommended_hypothesis_id": None,
        "recommended_hypothesis_status": None,
    }
    assert state["backlog_evolution_summary"]["recommended_action"] == "insufficient_backlog_signal"
    assert state["backlog_evolution_summary"]["ranked_candidates"] == []
    assert state["hypothesis_evolution_summary"]["recommended_action"] == "insufficient_hypothesis_signal"
    assert state["hypothesis_evolution_summary"]["ranked_hypotheses"] == []
    assert state["expansion_summary"] == {
        "expansion_ready": False,
        "recommended_experiment_id": None,
        "recommended_hypothesis_id": None,
        "risk_flags": [],
        "next_expansion_action": "insufficient_anchors",
        "status_headline": "The campaign has not established reusable backlog or hypothesis anchors yet.",
        "recommended_backlog_action": "insufficient_backlog_signal",
        "recommended_hypothesis_action": "insufficient_hypothesis_signal",
    }


def test_run_iteration_selects_objective_from_backlog_file(tmp_path: Path) -> None:
    target = tmp_path / "demo"
    runner.invoke(app, ["init", str(target), "--question", "Does X help Y?"])
    backlog_path = target / "backlog.json"
    _write_simple_backlog(backlog_path, best_objective="Selected backlog objective")

    seen_objectives: list[str] = []

    def fake_run_iteration(*, campaign_dir, planner, decomposer, launcher, verifier, governor, launcher_factory=None, initial_state=None):  # noqa: ANN001
        brief = planner({}, {})
        seen_objectives.append(brief.objective)
        tasks = decomposer(brief)
        verifier(
            brief,
            {"deliverable_paths": ["metrics.json"]},
            {
                "task_id": tasks[0]["task_id"],
                "worker_id": "claude_code",
                "status": "success",
                "deliverable_paths": ["metrics.json"],
                "summary": "created metrics.json",
            },
        )
        return "CONTINUE"

    with patch("controlplane.cli.run_iteration", side_effect=fake_run_iteration):
        result = runner.invoke(
            app,
            [
                "run-iteration",
                str(target),
                "--objective",
                "Fallback objective",
                "--backlog-file",
                str(backlog_path),
                "--deliverable",
                "metrics.json",
            ],
        )

    assert result.exit_code == 0
    assert len(seen_objectives) == 1
    assert seen_objectives[0].startswith("Selected backlog objective")

    state = json.loads((target / "campaign_state.json").read_text(encoding="utf-8"))
    rationale = state["campaign_backlog"]["last_selection"]["selection_rationale"]
    latest = json.loads((target / "latest_iteration.json").read_text(encoding="utf-8"))
    assert rationale["source"] == "backlog_file"
    assert rationale["selection_mode"] == "tracked_reprioritization"
    assert rationale["used_linked_hypothesis_state"] is True
    assert rationale["used_expansion_recommendations"] is True
    assert rationale["ranked_alternatives"][0]["frontier_age"] == "new"
    assert state["campaign_hypotheses"]["last_selection"]["selection_rationale"]["ranked_active_hypotheses"][0]["frontier_age"] == "new"
    assert "guided by the unproven / unproven / low / unproven / observe_insufficient_signal recommended anchor" in latest["objective"]
    assert "backlog recommendation state hint unproven / unproven / low / unproven / observe_insufficient_signal recommended anchor" in latest["brain_plan"]["reason"]


