def test_score_joint_pending_promotion_pair_prefers_persistent_pair_state() -> None:
    candidate = {
        "experiment_id": "exp_pair",
        "hypothesis_links": ["h_pair"],
        "status": "promising",
        "evolution_phase": "accelerating",
        "phase_strength": "medium",
        "trajectory_signal": "newly_accelerating",
        "action_mode": "promote_emerging_anchor",
    }
    backlog_summary = {
        "recommended_action": "investigate_pending_candidate_promotion",
        "pending_promotion_candidate_id": "exp_pair",
    }
    hypothesis_summary = {
        "recommended_action": "investigate_pending_hypothesis_promotion",
        "pending_promotion_hypothesis_id": "h_pair",
    }

    persistent_score = _score_joint_pending_promotion_pair(
        candidate,
        backlog_summary,
        hypothesis_summary,
        {
            "next_expansion_action": "investigate_pending_promotion_pair",
            "joint_pending_promotion_pair": {
                "experiment_id": "exp_pair",
                "hypothesis_id": "h_pair",
                "pressure_streak": 2,
                "pending_state": "persistent",
            },
        },
    )
    new_score = _score_joint_pending_promotion_pair(
        candidate,
        backlog_summary,
        hypothesis_summary,
        {
            "next_expansion_action": "investigate_pending_promotion_pair",
            "joint_pending_promotion_pair": {
                "experiment_id": "exp_pair",
                "hypothesis_id": "h_pair",
                "pressure_streak": 1,
                "pending_state": "new",
            },
        },
    )

    assert persistent_score > new_score


