def test_run_iteration_command_supports_subprocess_backed_backlog_selection_flow(tmp_path: Path) -> None:
    target = tmp_path / "demo"
    runner.invoke(app, ["init", str(target), "--question", "Does X help Y?"])

    backlog_path = target / "backlog.json"
    _write_simple_backlog(backlog_path, best_objective="Backlog-selected real execution objective")

    fake_ccb = tmp_path / "ccb"
    fake_ccb.write_text(
        "\n".join(
            [
                "#!/usr/bin/env python3",
                "from pathlib import Path",
                "import sys",
                "repo = Path(sys.argv[-1])",
                "(repo / 'metrics.json').write_text('{}', encoding='utf-8')",
                "print('created metrics.json from fake ccb backlog')",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    fake_ccb.chmod(0o755)

    env = os.environ.copy()
    env["PATH"] = str(tmp_path) + os.pathsep + env.get("PATH", "")

    with patch.object(ClaudeCodeLauncher, "_default_non_root_identity", return_value=(None, None)):
        result = runner.invoke(
            app,
            [
                "run-iteration",
                str(target),
                "--objective",
                "Fallback objective",
                "--backlog-file",
                str(backlog_path),
                "--deliverable",
                "metrics.json",
            ],
            env=env,
        )

    assert result.exit_code == 0
    payload = json.loads(result.stdout)
    assert payload["decision"] == "CONTINUE"
    assert payload["expansion_summary"]["next_expansion_action"] == "validate_low_confidence_anchor"
    assert payload["expansion_summary"]["backlog_ranked_alternatives"][0]["frontier_age"] == "new"
    assert payload["expansion_summary"]["hypothesis_ranked_alternatives"][0]["frontier_age"] == "new"

    latest = json.loads((target / "latest_iteration.json").read_text(encoding="utf-8"))
    assert latest["objective"].startswith("Backlog-selected real execution objective")

    state = json.loads((target / "campaign_state.json").read_text(encoding="utf-8"))
    rationale = state["campaign_backlog"]["last_selection"]["selection_rationale"]
    assert rationale["used_expansion_recommendations"] is True
    assert rationale["ranked_alternatives"][0]["frontier_age"] == "new"


