    assert "that is rising in the frontier" in latest["objective"]
    assert "that is holding its frontier position" in latest["objective"]
    assert "remains persistent in the frontier" in latest["brain_plan"]["reason"]
    assert "while rising in the frontier" in latest["brain_plan"]["reason"]
    assert "alternative exp_alt score signals status mixed, phase recovering, phase strength medium, trajectory newly_recovering, action mode promote_emerging_anchor" in latest["brain_plan"]["reason"]
    assert "is newly entering the frontier" in latest["brain_plan"]["reason"]
    assert "while holding its frontier position" in latest["brain_plan"]["reason"]
    assert "alternative h_alt score signals status mixed, phase stable, phase strength low, trajectory stale_stable, action mode validate_low_confidence_anchor" in latest["brain_plan"]["reason"]


