    fake_codex.write_text(
        "\n".join(
            [
                "#!/usr/bin/env python3",
                "from pathlib import Path",
                "repo = Path.cwd()",
                "(repo / 'metrics.json').write_text('{}', encoding='utf-8')",
                "(repo / 'result_note.md').write_text('Reserve hypothesis produced stronger evidence after serial review through the Codex backend.\\n', encoding='utf-8')",
                "print('codex promoted reserve hypothesis after serial review')",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    fake_codex.chmod(0o755)

    fake_ccb = tmp_path / "ccb"
    fake_ccb.write_text(
        "\n".join(
            [
                "#!/usr/bin/env python3",
                "print('claude review step prepared the reserve-hypothesis serial handoff')",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    fake_ccb.chmod(0o755)

    env = os.environ.copy()
    env["PATH"] = str(tmp_path) + os.pathsep + env.get("PATH", "")

    result = runner.invoke(
        app,
        [
            "run-campaign",
            str(target),
            "--resume",
            "--objective",
            "Fallback objective",
            "--decomposition-hint",
            "multi_worker_serial",
            "--worker-backend",
            "codex",
            "--deliverable",
            "metrics.json",
            "--deliverable",
            "result_note.md",
            "--max-rounds",
            "1",
        ],
        env=env,
    )

    assert result.exit_code == 0
    latest = json.loads((target / "latest_iteration.json").read_text(encoding="utf-8"))
    assert latest["worker_result"]["worker_id"] == "codex"
    assert latest["worker_result"]["status"] == "success"
    assert len(latest["task_packets"]) == 2
    assert latest["task_packets"][0]["task_type"] == "analysis"
    assert latest["task_packets"][1]["task_type"] == "code_and_run"
    assert latest["task_packets"][1]["worker_requirements"]["backend"] == "codex"
    task_results = latest["artifacts"]["task_results"]
    assert len(task_results) == 2
    assert task_results[0]["worker_id"] == "claude_code"
    assert task_results[1]["worker_id"] == "codex"
    assert sorted(latest["artifacts"]["deliverable_paths"]) == ["metrics.json", "result_note.md"]
    updated_state = json.loads((target / "campaign_state.json").read_text(encoding="utf-8"))
    assert updated_state["campaign_hypotheses"]["active_hypotheses"] == ["h_reserve"]
    hypothesis_rationale = updated_state["campaign_hypotheses"]["last_selection"]["selection_rationale"]
    assert hypothesis_rationale["selection_mode"] == "tracked_reprioritization"
    assert hypothesis_rationale["used_backlog_context"] is False


