    (target / "worker_registry.yaml").write_text(
        "\n".join(
            [
                "workers:",
                "  - worker_id: claude_code_primary",
                "    backend: claude_code",
                "    enabled: true",
                "    strengths: [coding, debugging, repo_navigation]",
                "    skills: [scientific_review, debugging, repo_write, experiment_execution]",
                "    trusted_for: [code_and_run, repair, analysis]",
                "  - worker_id: codex_secondary",
                "    backend: codex",
                "    enabled: true",
                "    strengths: [coding, debugging, repo_navigation]",
                "    skills: [scientific_review, debugging, repo_write, experiment_execution]",
                "    trusted_for: [code_and_run, analysis, repair]",
                "",
            ]
        ),
        encoding="utf-8",
    )

    fake_codex = tmp_path / "codex"
    fake_codex.write_text(
        "\n".join(
            [
                "#!/usr/bin/env python3",
                "from pathlib import Path",
                "repo = Path.cwd()",
                "(repo / 'metrics.json').write_text('{}', encoding='utf-8')",
                "(repo / 'result_note.md').write_text('Persistent coordination divergence was resolved after serial review through the Codex backend on single iteration resume.\\n', encoding='utf-8')",
                "print('codex resolved persistent coordination divergence after serial review on iteration resume')",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    fake_codex.chmod(0o755)

    fake_ccb = tmp_path / "ccb"
    fake_ccb.write_text(
        "\n".join(
            [
                "#!/usr/bin/env python3",
                "print('claude review step prepared the coordination-divergence serial handoff for iteration resume')",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    fake_ccb.chmod(0o755)

    env = os.environ.copy()
    env["PATH"] = str(tmp_path) + os.pathsep + env.get("PATH", "")

    result = runner.invoke(
        app,
        [
            "run-iteration",
            str(target),
            "--resume",
            "--objective",
            "Fallback objective",
            "--decomposition-hint",
            "multi_worker_serial",
            "--worker-backend",
            "codex",
            "--deliverable",
            "metrics.json",
            "--deliverable",
            "result_note.md",
        ],
        env=env,
    )

    assert result.exit_code == 0
    latest = json.loads((target / "latest_iteration.json").read_text(encoding="utf-8"))
    assert latest["worker_result"]["worker_id"] == "codex"
    assert latest["worker_result"]["status"] == "success"
    assert "resolve_persistent_coordination_divergence" in latest["brain_plan"]["reason"]
    assert len(latest["task_packets"]) == 2
    assert latest["task_packets"][0]["task_type"] == "analysis"
    assert latest["task_packets"][1]["task_type"] == "code_and_run"
    assert latest["task_packets"][1]["worker_requirements"]["backend"] == "codex"
    task_results = latest["artifacts"]["task_results"]
    assert len(task_results) == 2
    assert task_results[0]["worker_id"] == "claude_code"
    assert task_results[1]["worker_id"] == "codex"
    assert latest["task_intent"]["task_type"] == "analysis"
    assert latest["task_intent"]["acceptance_emphasis"] == "scientific_validity"
    assert "reconcile_anchor_signals" in latest["task_intent"]["focus_areas"]
    assert "persistent_coordination_divergence_resolution" in latest["task_intent"]["focus_areas"]
    assert sorted(latest["artifacts"]["deliverable_paths"]) == ["metrics.json", "result_note.md"]


