    assert "stabilize_persistent_joint_recovery_pair" in latest["brain_plan"]["reason"]
    assert "joint recovery pair exp_best/h_best is persistent" in latest["brain_plan"]["reason"]
    assert "scientific_validity" in latest["brain_plan"]["reason"]
    assert "joint_recovery_pair" in latest["brain_plan"]["focus_areas"]
    assert "keep exp_alt in reserve as a persistent backlog alternative that is rising in the frontier" in latest["objective"]
    assert "keep h_alt in reserve as a newly-entered active hypothesis alternative that is holding its frontier position" in latest["objective"]
    assert "selected anchor score signals status blocked, phase regressing, phase strength medium, trajectory newly_regressing, action mode reroute_for_stronger_evidence" in latest["brain_plan"]["reason"]
    assert "selected hypothesis anchor score signals status unstable, phase regressing, phase strength low, trajectory newly_regressing, action mode recover_missing_artifacts" in latest["brain_plan"]["reason"]
    assert "backlog alternative exp_alt is currently suppressed by weaker_phase_strength" in latest["brain_plan"]["reason"]
    assert "while rising in the frontier" in latest["brain_plan"]["reason"]
    assert "active hypothesis alternative h_alt is currently suppressed by stale_trajectory" in latest["brain_plan"]["reason"]
    assert "while holding its frontier position" in latest["brain_plan"]["reason"]


