def test_run_campaign_real_scientific_validity_failure_reselection_updates_recovery_handoff_to_new_anchor(
    tmp_path: Path,
) -> None:
    target = tmp_path / "demo"
    runner.invoke(app, ["init", str(target), "--question", "Does X help Y?"])
    backlog_path = target / "backlog.json"
    backlog_path.write_text(
        json.dumps(
            [
                {
                    "experiment_id": "exp_seed",
                    "objective": "Seed evidence objective",
                    "hypothesis_links": ["h_seed"],
                    "expected_information_gain": 0.8,
                    "risk_reduction": 0.5,
                    "cost_score": 0.2,
                },
                {
                    "experiment_id": "exp_healthier",
                    "objective": "Healthier evidence objective",
                    "hypothesis_links": ["h_healthier"],
                    "expected_information_gain": 0.79,
                    "risk_reduction": 0.49,
                    "cost_score": 0.2,
                },
            ]
        )
        + "\n",
        encoding="utf-8",
    )

    fake_ccb = tmp_path / "ccb"
    fake_ccb.write_text(
        "\n".join(
            [
                "#!/usr/bin/env python3",
                "from pathlib import Path",
                "import json",
                "import sys",
                "repo = Path(sys.argv[-1])",
                "state_file = repo / 'scientific_reselection_handoff_phase.json'",
                "state = json.loads(state_file.read_text(encoding='utf-8')) if state_file.exists() else {'phase': 1}",
                "phase = state['phase']",
                "if phase == 1:",
                "    (repo / 'metrics.json').write_text('{}', encoding='utf-8')",
                "    (repo / 'result_note.md').write_text('short note', encoding='utf-8')",
                "    print('short summary')",
                "    state['phase'] = 2",
                "elif phase == 2:",
                "    (repo / 'result_note.md').write_text('weak note', encoding='utf-8')",
                "    print('short summary')",
                "    state['phase'] = 3",
                "else:",
                "    (repo / 'metrics.json').write_text('{}', encoding='utf-8')",
                "    (repo / 'result_note.md').write_text('The results suggest the metric evidence is stronger because the finding was observed, the healthier candidate remained supported, and the explanation improved after the scientific-validity recovery step.', encoding='utf-8')",
                "    print('The results suggest the metric evidence is stronger because the finding was observed, the healthier candidate remained supported, and the explanation improved after the scientific-validity recovery step.')",
                "state_file.write_text(json.dumps(state), encoding='utf-8')",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    fake_ccb.chmod(0o755)
    env = os.environ.copy()
    env["PATH"] = str(tmp_path) + os.pathsep + env.get("PATH", "")

    with patch.object(ClaudeCodeLauncher, "_default_non_root_identity", return_value=(None, None)):
        result = runner.invoke(
            app,
            [
                "run-campaign",
                str(target),
                "--objective",
                "Fallback objective",
                "--backlog-file",
                str(backlog_path),
                "--deliverable",
                "metrics.json",
                "--deliverable",
                "result_note.md",
                "--max-rounds",
                "3",
            ],
            env=env,
        )

    assert result.exit_code == 0
    latest = json.loads((target / "latest_iteration.json").read_text(encoding="utf-8"))
    assert "fallback recovery guidance derived from the known failed check types" in latest["brain_plan"]["reason"]
    assert "scientific_validity" in latest["brain_plan"]["reason"]
    assert latest["objective"].startswith("Healthier evidence objective")
    assert "Use the new candidate as the recovery anchor" in latest["objective"]
    assert "prioritize scientific_validity recovery" in latest["objective"]
    assert latest["brain_plan"]["strategy"] == "refine"
    assert latest["experiment_brief"]["hypothesis_links"] == ["h_healthier"]
    state = json.loads((target / "campaign_state.json").read_text(encoding="utf-8"))
    assert state["campaign_backlog"]["active_candidate"] == {
        "experiment_id": "exp_healthier",
        "objective": "Healthier evidence objective",
        "hypothesis_links": ["h_healthier"],
    }
    assert state["campaign_hypotheses"]["active_hypotheses"] == ["h_healthier"]
    assert state["backlog_evolution_summary"]["recommended_action"] == "promote_promising_candidate"


def test_run_campaign_command_prints_decision_sequence_and_campaign_summary(tmp_path: Path) -> None:
    target = tmp_path / "demo"
    runner.invoke(app, ["init", str(target), "--question", "Does X help Y?"])

    with patch("controlplane.cli.run_campaign_loop", return_value=["CONTINUE", "STOP"]):
        result = runner.invoke(
            app,
            [
                "run-campaign",
                str(target),
                "--objective",
                "Create metrics.json",
                "--deliverable",
                "metrics.json",
                "--max-rounds",
                "3",
            ],
        )

    assert result.exit_code == 0
    payload = json.loads(result.stdout)
    assert payload["campaign_dir"] == str(target)
    assert payload["decisions"] == ["CONTINUE", "STOP"]
    assert payload["expansion_summary"] == {
        "expansion_ready": False,
        "recommended_experiment_id": None,
        "recommended_hypothesis_id": None,
        "risk_flags": [],
        "next_expansion_action": "insufficient_anchors",
        "status_headline": "The campaign has not established reusable backlog or hypothesis anchors yet.",
        "recommended_backlog_action": "insufficient_backlog_signal",
        "recommended_backlog_action_mode": "observe_insufficient_signal",
        "recommended_hypothesis_action": "insufficient_hypothesis_signal",
        "backlog_phase_strength_signal": "low",
        "backlog_recommendation_drivers": {
            "phase": "unproven",
            "phase_strength": "low",
            "trajectory_signal": "unproven",
            "action_mode": "observe_insufficient_signal",
            "status": "unproven",
            "recommendation_state_hint": "unproven / unproven / low / unproven / observe_insufficient_signal recommended anchor",
        },
    }

    state = json.loads((target / "campaign_state.json").read_text(encoding="utf-8"))
    assert state["iterations_run"] == 2
    assert state["last_decision"] == "STOP"
    assert state["campaign_summary"] == {
        "research_question": "Does X help Y?",
        "status_headline": "The campaign has completed 2 rounds for the current research question.",
        "latest_outcome": "pending_review",
        "next_step": "Review the analysis output and decide whether to continue, refine, hold, or escalate.",
        "latest_failed_check_types": [],
        "blocking_issue": None,
        "resume_ready": True,
        "resume_reasons": [],
    }
    assert state["campaign_memory"] == {
        "latest_accepted_objective": None,
        "latest_accepted_summary": None,
        "latest_accepted_artifacts": [],
        "latest_accepted_iteration_outcome": None,
    }
    assert state["memory_summary"] == {
        "preferred_artifact": None,
        "evidence_summary": None,
        "accepted_memory_ready": False,
    }
    assert state["continuation_anchor"] == {
        "anchor_artifact": None,
        "anchor_objective": None,
        "anchor_summary": None,
        "anchor_ready": False,
    }
    assert state["campaign_lifecycle"] == "stopped"

    log_lines = (target / "iteration_log.jsonl").read_text(encoding="utf-8").strip().splitlines()
    assert len(log_lines) == 2
    first = json.loads(log_lines[0])
    second = json.loads(log_lines[1])
    assert first["brain_plan"]["strategy"] == "continue"
    assert second["brain_plan"]["strategy"] == "continue"

    assert state["expansion_summary"]["backlog_recommendation_drivers"] == {
        "phase": "unproven",
        "phase_strength": "low",
        "trajectory_signal": "unproven",
        "action_mode": "observe_insufficient_signal",
        "status": "unproven",
        "recommendation_state_hint": "unproven / unproven / low / unproven / observe_insufficient_signal recommended anchor",
    }


def test_status_command_surfaces_anchor_coherence_reconcile_snapshot(tmp_path: Path) -> None:
    target = tmp_path / "demo"
    runner.invoke(app, ["init", str(target), "--question", "Does X help Y?"])

    state = json.loads((target / "campaign_state.json").read_text(encoding="utf-8"))
    state["campaign_lifecycle"] = "in_progress"
    state["campaign_summary"]["latest_outcome"] = "accepted"
    state["campaign_backlog"] = {
        "selection_ready": True,
        "active_candidate": {
            "experiment_id": "exp_primary",
            "objective": "Primary objective",
            "hypothesis_links": ["h_primary"],
        },
    }
    state["campaign_hypotheses"] = {
        "selection_ready": True,
        "active_hypotheses": ["h_other"],
    }
    state["backlog_summary"] = {
        "selection_ready": True,
        "active_experiment_id": "exp_primary",
        "active_objective": "Primary objective",
        "promising_candidates": ["exp_primary"],
        "blocked_candidates": [],
        "unproven_candidates": [],
        "recommended_anchor_experiment_id": "exp_primary",
        "recommended_anchor_status": "promising",
        "recommended_anchor_hypothesis_links": ["h_primary"],
    }
    state["hypothesis_summary"] = {
        "selection_ready": True,
        "active_hypotheses": ["h_other"],
        "supported_hypotheses": ["h_other"],
        "unstable_hypotheses": [],
        "mixed_hypotheses": [],
        "unknown_hypotheses": [],
        "recommended_hypothesis_id": "h_other",
        "recommended_hypothesis_status": "supported",
    }
    state["backlog_evolution_summary"] = {
        "recommended_experiment_id": "exp_primary",
        "recommended_action": "promote_promising_candidate",
        "recommended_action_mode": "validate_low_confidence_anchor",
        "advancing_candidates": ["exp_primary"],
        "regressing_candidates": [],
        "recovery_candidates": [],
        "accelerating_candidates": [],
        "stable_candidates": ["exp_primary"],
        "phase_strength_signal": "low",
    }
    state["hypothesis_evolution_summary"] = {
        "recommended_hypothesis_id": "h_other",
        "recommended_action": "promote_supported_hypothesis",
        "recommended_action_mode": "validate_low_confidence_anchor",
        "advancing_hypotheses": ["h_other"],
        "regressing_hypotheses": [],
        "recovery_hypotheses": [],
        "accelerating_hypotheses": [],
        "stable_hypotheses": ["h_other"],
        "phase_strength_signal": "low",
    }
    state["expansion_summary"] = {
        "expansion_ready": True,
        "recommended_experiment_id": "exp_primary",
        "recommended_hypothesis_id": "h_other",
        "risk_flags": [],
        "next_expansion_action": "reconcile_anchor_signals",
        "status_headline": "The recommended backlog anchor and hypothesis anchor should be reconciled before broader expansion.",
        "recommended_backlog_action": "promote_promising_candidate",
        "recommended_hypothesis_action": "promote_supported_hypothesis",
        "recommended_backlog_action_mode": "validate_low_confidence_anchor",
        "recommended_hypothesis_action_mode": "validate_low_confidence_anchor",
        "anchor_coherence": "divergent",
        "anchor_coherence_expected_hypothesis_ids": ["h_primary"],
        "anchor_coherence_selected_hypothesis_id": "h_other",
    }
    (target / "campaign_state.json").write_text(json.dumps(state, indent=2) + "\n", encoding="utf-8")

    status = runner.invoke(app, ["status", str(target)])

    assert status.exit_code == 0
    payload = json.loads(status.stdout)
    assert payload["expansion_summary"]["next_expansion_action"] == "reconcile_anchor_signals"
    assert payload["expansion_summary"]["anchor_coherence"] == "divergent"
    assert payload["expansion_summary"]["anchor_coherence_expected_hypothesis_ids"] == ["h_primary"]
    assert payload["expansion_summary"]["anchor_coherence_selected_hypothesis_id"] == "h_other"
    assert "recommended backlog anchor and hypothesis anchor should be reconciled" in payload["expansion_summary"]["status_headline"]


