    assert latest["task_intent"]["acceptance_emphasis"] == "scientific_validity"
    assert "reconcile_anchor_signals" in latest["task_intent"]["focus_areas"]
    assert sorted(latest["artifacts"]["deliverable_paths"]) == ["metrics.json", "result_note.md"]


